import "sort"

func bucketSort(arr []float64) {
	n := len(arr)
	if n <= 0 {
		return
	}
	buckets := make([][]float64, n)
	for i := 0; i < n; i++ {
		idx := int(arr[i] * float64(n))
		buckets[idx] = append(buckets[idx], arr[i])
	}
	for i := 0; i < n; i++ {
		sort.Float64s(buckets[i])
	}
	index := 0
	for i := 0; i < n; i++ {
		for j := 0; j < len(buckets[i]); j++ {
			arr[index] = buckets[i][j]
			index++
		}
	}
}

