#include <stdlib.h>

struct Node {
	float data;
	struct Node* next;
};

void bucketSort(float arr[], int n) {
	struct Node** buckets = (struct Node**)calloc(n, sizeof(struct Node*));
	for (int i = 0; i < n; i++) {
		int idx = n * arr[i];
		struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
		newNode->data = arr[i];
		newNode->next = NULL;
		struct Node* curr = buckets[idx];
		struct Node* prev = NULL;
		while (curr != NULL && curr->data <= arr[i]) {
			prev = curr;
			curr = curr->next;
		}
		if (prev == NULL) {
			newNode->next = buckets[idx];
			buckets[idx] = newNode;
		} else {
			newNode->next = curr;
			prev->next = newNode;
		}
	}
	int index = 0;
	for (int i = 0; i < n; i++) {
		struct Node* curr = buckets[i];
		while (curr != NULL) {
			arr[index++] = curr->data;
			struct Node* temp = curr;
			curr = curr->next;
			free(temp);
		}
	}
	free(buckets);
}
